-- ЮЛ + Эквайринг для Потока 2. Запускать, когда стартует поток юрлиц.
alter table public.cases add column if not exists track text not null default 'fl';

-- Игра «Эквайринг» есть только в потоке ЮЛ. Заводим её ДО кейсов, иначе
-- insert ниже падал на FK cases.game_id → games.id (игры не существовало).
-- status='locked' + отдельный поток: на доску ФЛ выводить её не нужно
-- (фильтрацию потоков сделать при старте Потока 2).
on conflict (id) do nothing;

