insert into public.games (id, num, week, title, skill, emoji, accent, status) values
  ('acquiring', 8, 8, 'Эквайринг', 'Работа с торговым эквайрингом', '💳', '#0aa5a5', 'locked')
insert into public.cases (game_id, ord, title, difficulty, body, track) values
  ('detective', 1, 'Кэшбэк по программе лояльности не начислился', 'Лёгкий', 'Я уже три недели пользуюсь программой лояльности «Альфа-Выгодно для бизнеса», купил товары на 80 тысяч — а баллы не начислились! Я же всё сделал, как в рекламе! Вы мне обещали 10% кэшбэк — где баллы? Это жульничество!', 'ul'),
  ('detective', 2, 'Перевод с кредитной карты на дебетовую', 'Средний', 'Я только что попытался перевести 150 000 руб. со своей кредитной карты Business One Credit себе на дебетовую карту. Почему операция не проходит? У меня есть лимит, я не в просрочке — что мне делать?!', 'ul'),
  ('detective', 3, 'Нулевой налог УСН в «Бухгалтерии»', 'Сложный', 'Я ИП на УСН «Доходы», в сервисе «Бухгалтерия» пишет: «К оплате: 0 рублей» и предлагает отправить уведомление с нулевой суммой. Это ошибка? Или я что-то не понимаю? Почему банк говорит, что платить не надо, если я вообще не платил?', 'ul'),
  ('detective', 4, 'Отказ кассира принять заемные средства', 'Средний', 'Я пришёл в отделение банка с 2 млн рублей, хочу внести на счёт компании как заемные средства. Кассир отказала, сказала: «Мы не можем принять». Что делать?', 'ul'),
  ('detective', 5, 'Не отправляется платёж в Китай', 'Сложный', 'Я отправил платёж в Китай на 120 000 юаней — и он не отправился. Что я сделал не так?', 'ul'),
  ('detective', 6, 'Возврат рублёвого платежа по 173-ФЗ', 'Сложный', 'Я отправил платёж в рублях на счёт иностранной компании в Казахстан, назначение «оплата за консультации». Банк вернул платёж с ошибкой «Нарушение требований 173-ФЗ». Я не понимаю — ведь это не валютный перевод, это же рубли! Почему банк требует какие-то документы? Я же не экспортер, я просто оплачиваю услуги! Что мне делать?', 'ul'),
  ('detective', 7, 'Нет сдачи при взносе наличных', 'Средний', 'Я пришла в офис банка внести 118 000 рублей на счёт компании — у меня только купюры по 5 000 рублей. Кассир говорит, что нужно внести сумму больше, так как сдачи нет. Разменять мне негде, а платёж поставщику — через час. Что мне делать?', 'ul'),
  ('detective', 8, 'Изменение суммы контракта на учёте', 'Сложный', 'Я заключил контракт и он уже принят на учёт — но теперь поставщик изменил сумму контракта. Я не могу ничего изменить, поставщик угрожает расторжением договора. Что делать?', 'ul'),
  ('detective', 9, 'Автоувольнение сотрудника из зарплатного проекта', 'Средний', 'Мой сотрудник пришёл ко мне в офис и сказал, что его отключили от зарплатных условий. Мне нужно сейчас ему начислить отпускные, почему банк решил за меня уволить? Вы же должны были дождаться моего указания, а не действовать сами!', 'ul'),
  ('detective', 10, 'Задержка доставки зарплатных карт', 'Лёгкий', 'Я заказал доставку зарплатных карт для сотрудников — указал дату и адрес, всё подтверждено. Прошло 3 дня, ни одна карта не доставлена, ни один банкир не позвонил. Когда приедут и доставят карты?', 'ul'),
  ('noforward', 1, 'Счёт заблокирован после уплаты налога', 'Сложный', 'Я только что получил SMS, что на счёте заблокировано 1,2 млн рублей — налоговая требует оплату, но я уже всё заплатил! Я проверил в личном кабинете ФНС — там стоит «Задолженность погашена». Почему банк до сих пор не разблокировал счёт? Я не могу платить зарплату сотрудникам, это катастрофа! Вы же должны сразу снимать ограничения, как только налоговая обновит статус!', 'ul'),
  ('noforward', 2, 'Долгая проверка документов по 115-ФЗ', 'Средний', 'Я уже давно отправила документы по запросу 115-ФЗ, их все никак банк не может проверить. Сколько еще ждать? ', 'ul'),
  ('noforward', 3, 'Задержка справки об открытии счёта', 'Средний', 'Я неделю жду справку об открытии счета — отправил запрос в интернет-банк, но до сих пор ничего не пришло. Мне её срочно нужно предоставить в налоговую на бумажном носителе с синей печатью. ', 'ul'),
  ('noforward', 4, 'Не подгружается зарплатная ведомость', 'Средний', 'Как связаться с зарплатным менеджером? Ведомость не подгружается, что делать? ', 'ul'),
  ('noforward', 5, 'Счёт заблокирован, налоговая сняла ограничения', 'Средний', 'Я только что попытался перевести платеж контрагенту — счёт заблокирован. Налоговая сказала, решение о снятии ограничений отправила, но у вас ничего не изменилось! Я не понимаю, почему вы не обрабатываете документы вовремя? Мне срочно нужно заплатить — они ждут!', 'ul'),
  ('noforward', 6, 'Недоступен лимит овердрафта', 'Средний', 'Почему лимит овердрафта не доступен, у меня же нет никаких ограничений по счёту? ', 'ul'),
  ('noforward', 7, 'Срочная отмена платежа', 'Средний', 'Мне срочно нужно отменить платеж, пока деньги еще не списались. Что мне для этого нужно сделать? ', 'ul'),
  ('noforward', 8, 'Не найти заявку на бизнес-кредит', 'Средний', 'Я хочу оформить бизнес-кредит — у меня есть выручка, стабильные обороты, счёт работает, но, когда я зашёл в интернет-банк, не нашел, где можно подать заявку. Я звонил в КЦ — мне сказали: «Обратитесь к своему менеджеру». Почему вы не помогаете, а только перекладываете?', 'ul'),
  ('noforward', 9, 'Не дозвониться до валютного контролёра', 'Средний', 'Я уже три дня пытаюсь дозвониться до валютного контролера, оставляю заявки, но никто не отвечает! Мне нужно отправить платёж, я не знаю, какой код валютной операции ставить — в интернет-банке написано «укажите код», но нет подсказки. ', 'ul'),
  ('noforward', 10, 'Не зачислилось внесение через банкомат', 'Средний', 'Я внес в вашем банкомате 500 000 рублей по бизнес-карте, не зачислилось 10 000 рублей. Я проверял чек — сумма правильная, кассир в отделении банка тоже это подтвердил. Я уже два дня жду, когда вы мне их начислите. ', 'ul'),
  ('iknow', 1, 'Нет доступа в зарплатный проект', 'Лёгкий', 'У нас в компании поменялся руководитель, в интернет-банк он уже зашел, но в Зарплатный проект доступа нет почему-то! Сколько ещё ждать? ', 'ul'),
  ('iknow', 2, 'Банк отменил платёж в Китай', 'Средний', 'Мы отправили платёж в Китай на 200 000 юаней, но банк по какой-то причине отменил его и даже не отправил! Вы не работаете с банком, в который мы направили деньги? ', 'ul'),
  ('iknow', 3, 'Дивиденды с кредитной карты не прошли', 'Средний', 'Я оформила кредитную карту и планировала перевести учредителю дивиденды, но такой перевод не прошел. Что случилось? ', 'ul'),
  ('iknow', 4, 'Счёт заблокирован после смены директора', 'Сложный', 'У нас в компании изменился директор, мы подали все документы в налоговую. Почему счёт заблокирован? ', 'ul'),
  ('iknow', 5, 'Интернет-банк не грузит', 'Лёгкий', 'Я уже час пытаюсь зайти в ваш интернет-банк, у меня он не открывается, страница совершенно не грузит! Что у вас за технический сбой? ', 'ul'),
  ('iknow', 6, 'Бизнес-карта не привязалась к счёту', 'Средний', 'Я получил бизнес-карту, но по каким-то причинам она не привязалась к счёту, я не вижу её в приложении. Мне что, нужно ещё раз идти в офис и оформлять новую карту? ', 'ul'),
  ('iknow', 7, 'Комиссия за снятие в чужом банкомате', 'Лёгкий', 'Хочу снять наличиные по бизнес-карте, но в банкомате другого банка. Какая будет комиссия? ', 'ul'),
  ('iknow', 8, 'Не прошло начисление зарплаты', 'Средний', 'Почему у меня не прошло начисление зарплаты сотрудникам, деньги с моего счёта списали! Мои сотрудники ждут целый день! Что у вас там случилось? ', 'ul'),
  ('iknow', 9, 'Возврат комиссии за обслуживание', 'Сложный', '1 числа у меня списалась комиссия за обслуживание счёта 69 990 рублей! Верните мне комиссию, я не хочу платить на год вперед. Требую вернуть мои деньги.', 'ul'),
  ('iknow', 10, 'Непонятное списание 1500 рублей', 'Лёгкий', 'Что за сумму у меня списал Альфа Банк? Списали 1500 рублей! За что опять вы взимаете комиссии, сколько уже можно, это невыносимо! ', 'ul'),
  ('empathy', 1, 'Автоматическая разметка платежей АУСН', 'Средний', 'Я уже три дня не сплю — банк автоматически пометил все мои платежи как доходы, даже те, что идут на аренду и закупки! Я не понимаю, почему ФНС считает, что я зарабатываю больше, чем реально, и теперь мне грозит штраф. Я же всё делал по правилам, а вы просто «автоматом» всё испортили! Что вы со мной сделаете?', 'ul'),
  ('empathy', 2, 'Задержка разблокировки счёта после ФНС', 'Средний', 'Налоговая все разблокировала! Когда разблокируете вы? Я уже три дня не могу платить поставщикам, у меня штрафы накапливаются — вы же видите, что ФНС всё сняла, почему вы до сих пор ничего не делаете?', 'ul'),
  ('empathy', 3, 'Платёж не отменился после «Отозвать»', 'Средний', 'Почему платёж не отменился? Я же нажал кнопку «Отозвать»! Я же не виноват, что вы так быстро отправляете деньги. Вы хоть понимаете, что я потерял доверие к вашему банку?', 'ul'),
  ('empathy', 4, 'Сбой при отправке зарплаты', 'Сложный', 'Я уже полчаса пытаюсь отправить зарплату сотрудникам — система пишет «Ошибка соединения», перезагружаю, пробую с телефона — ничего не работает! У меня через 20 минут дедлайн, а люди ждут зарплату! Вы вообще понимаете, что у меня сейчас паника? Это же ваш банк, а не я виноват, что у вас сбой!', 'ul'),
  ('empathy', 5, 'Не подходит пароль в интернет-банк', 'Средний', 'Я уже второй час пытаюсь зайти в интернет-банк — ввожу свой пароль, но он не подходит! А я же срочно должен перевести деньги поставщику, у меня штраф! Вы вообще понимаете, что я не знаю, что делать?', 'ul'),
  ('empathy', 6, 'Платёж «Исполнен», но не дошёл', 'Сложный', 'Я отправил платёж поставщику на 1,2 млн рублей — в системе написано «Исполнен», а у них до сих пор ничего не пришло! Они уже требуют штраф за просрочку, а я им не могу доказать, что деньги отправил! Вы же видите — статус «Исполнен», значит, всё должно быть! Почему вы не можете сразу сказать, когда они придут? Я уже третий раз обращаюсь к вам. ', 'ul'),
  ('empathy', 7, 'Блокировка счёта по 115-ФЗ', 'Сложный', 'У меня заблокировали счёт, я не знаю почему! Я не мошенник, не преступник — я просто веду бизнес, покупаю товары, плачу поставщикам! А вы пишете: «Счёт заблокирован по 115-ФЗ» — как будто я что-то скрываю. Вы вообще понимаете, что я сейчас теряю всё?', 'ul'),
  ('empathy', 8, 'Не пришёл платёж от партнёра', 'Средний', 'Мы ждём 1,5 млн от партнёра — он говорит, что отправил платёж еще вчера, а у нас до сих пор ничего! Я проверил — в выписке нет. Он прислал мне скрин с «Исполнен» — но я его не вижу! Вы же банк, вы должны видеть все платежи! У меня сейчас критический дефицит денег, я не могу заплатить зарплату, а вы просто говорите: «Подождите». Вы вообще понимаете, что мы на грани?', 'ul'),
  ('empathy', 9, 'Неожиданная комиссия за карту', 'Сложный', 'Менеджер при открытии счета обещал, что обслуживание карты Business One будет бесплатным. А сейчас вдруг списали 242 рубля! Я не просил и не соглашался! Вы вообще понимаете, что это обман? Я требую зарегистрировать претензию на менеджера — и вернуть деньги. Я больше не доверяю вашему банку!', 'ul'),
  ('empathy', 10, 'Блокировка карты без предупреждения', 'Лёгкий', '«Это просто позор! Меня поставили в неловкое положение перед людьми! Ваш банк заблокировал карту без каких-либо предупреждений! Я требую объяснений и компенсации!»', 'ul'),
  ('onecall', 1, 'Декларация УСН за 2025 год', 'Сложный', 'Я ИП на УСН «Доходы», уже сдал декларацию за 2024 год, но вчера в личном кабинете вдруг увидел, что сервис предлагает сформировать декларацию за 2025 год — я не понимаю, почему она не сформировалась автоматически. Я уже заплатил все взносы, но в системе они не отображаются. Я боюсь, что не успею подать до 25 апреля, а мне сказали, что если не подать — будет штраф. Что мне делать прямо сейчас?', 'ul'),
  ('onecall', 2, 'Мошенник выманил CVV', 'Средний', 'Клиент сообщает, что позвонил ''сотрудник службы безопасности'' и попросил сообщить CVV и код из СМС. Клиент успел назвать CVV, но код из СМС — нет. Спрашивает, что делать.', 'ul'),
  ('onecall', 3, 'Справка об оборотах по счёту', 'Лёгкий', 'Мне срочно нужна справка об оборотах по счёту — я уже три дня ищу, как её получить, а в приложении не вижу нужного пункта. Можно ли это сделать прямо сейчас, чтобы не ехать в отделение?', 'ul'),
  ('onecall', 4, 'Заказ бизнес-карты', 'Лёгкий', 'У меня уже есть счёт в Альфа-Банке, но я до сих пор не оформил бизнес-карту — мне нужно снимать наличные в банкоматах. Как мне ее заказать и как долго ждать? ', 'ul'),
  ('onecall', 5, 'Перевод ИП на личный счёт', 'Средний', 'Я ИП, хочу перевести 300 000 руб. со своего расчётного счёта в Альфа-Банке на свой личный счёт физлица — менеджер сказал, что будет 1% комиссия, но я слышал, что до 300 тыс. можно бесплатно. Я не уверен, как это работает — можно ли сделать этот перевод без комиссии прямо сейчас, и где проверить, сколько я уже перевёл этого месяца?', 'ul'),
  ('onecall', 6, 'Смена тарифа обслуживания', 'Средний', 'У меня сейчас тариф «0 за обслуживание» — я его выбрал, когда только открыл бизнес, но теперь оборот вырос, и я хочу перейти на «Быстрое развитие», чтобы получать больше лимитов на переводы. Когда можно поменять тариф, чтобы не платить лишнего, и можно ли это сделать прямо сейчас? ', 'ul'),
  ('onecall', 7, 'Постановка контракта на учёт', 'Сложный', 'У меня импортный контракт на 3,2 млн руб. с китайским поставщиком — мне нужно его поставить на учёт в банке, иначе не смогу оплатить. Я уже пытался подгрузить документы в интернет-банк, но не понял, где поставить галочку «Присвоить УНК». Можно ли это сделать прямо сейчас, чтобы к завтрашнему дню контракт был учтён, и я смог перевести деньги?', 'ul'),
  ('onecall', 8, 'Бухгалтер в зарплатный проект', 'Средний', 'Я хочу добавить бухгалтера в зарплатный проект — чтобы он мог подписывать ведомости, а не только я как руководитель. Я не знаю, как это сделать, и что нужно отправить. Менеджер сказал, что нужно заявление и паспорт, но я не понял, какие страницы и куда загружать. Можно это сделать прямо сейчас, чтобы завтра бухгалтер уже мог работать?', 'ul'),
  ('onecall', 9, 'Платёж юрлицу в другой банк', 'Лёгкий', 'Я хочу перевести 850 000 руб. поставщику — это юрлицо, счёт в другом банке. Можно ли сделать такой платеж и приложении и когда платеж уйдёт — сегодня или завтра? ', 'ul'),
  ('onecall', 10, 'Перевод не тому получателю', 'Средний', 'Клиент перевёл 50 000 рублей не тому получателю — ошибся в одной цифре номера счёта. Деньги ушли 10 минут назад. Просит вернуть.', 'ul'),
  ('captains', 1, 'Счёт не разблокировали, срочная оплата', 'Средний', 'У клиента не разблокировали счёт, необходимо оплатить контрагенту. В налоговой решение о снятии блокировки уже направили. ', 'ul'),
  ('captains', 2, 'SMS о подтверждении платежа', 'Лёгкий', 'Клиенту пришла смс о том, что нужно обратиться в банк для подтверждения платежа. ', 'ul'),
  ('captains', 3, 'Перевод не тому получателю', 'Сложный', 'Клиент перевёл 500 000 рублей не тому получателю — ошибся в одной цифре номера счёта. Деньги ушли 10 минут назад. Просит вернуть.', 'ul'),
  ('captains', 4, 'Заблокирован доступ в интернет-банк', 'Лёгкий', 'Клиент не может войти в интернет-банк — пишет ошибка "Доступ заблокирован". ', 'ul'),
  ('captains', 5, 'Комиссия за обслуживание карты', 'Средний', 'Клиент обнаружил, что с него удержана комиссия 242,78 рублей за обслуживание карты. Считает, что карта у него бесплатная и комиссия списалась некорекктно. Требует возврата и объяснений.', 'ul'),
  ('captains', 6, 'Недовольство комиссией за счёт', 'Лёгкий', 'Клиент не доволен комиссией за обслуживание счёта, сообщает, что почти им не пользуется и не готов платить такую высокую комиссию.', 'ul'),
  ('captains', 7, 'Новичок не умеет делать платёж', 'Лёгкий', 'Клиент недавно открыл счёт и не понимает, как работать в интернет-банке, а ему нужно перевести оплату за поставленный товар.', 'ul'),
